# -- Helpers --
import textwrap as _tw

_LINE_WIDTH = 70

def _banner(title):
    print("=" * _LINE_WIDTH)
    pad = (_LINE_WIDTH - len(title) - 2) // 2
    print(" " * pad + " " + title + " " + " " * pad)
    print("=" * _LINE_WIDTH)

def _hr():
    print("-" * _LINE_WIDTH)

def _wrap(text):
    return _tw.wrap(text, width=_LINE_WIDTH - 4,
                    initial_indent="  ", subsequent_indent="    ")

def _show_wrong(raw, wrong_dict):
    exp = wrong_dict.get(raw)
    if exp:
        print()
        for ln in _wrap(f"[wrong] {exp}"):
            print(ln)
    else:
        print(f"  [wrong] {raw!r} is not the correct answer.")

def _show_passphrase(passphrase):
    print()
    _hr()
    print(f"  Passphrase: {passphrase}")
    _hr()
    print()


SCRIPT_DIR = os.path.dirname(os.path.abspath(__file__))
REPO_ZIP   = os.path.join(SCRIPT_DIR, "repo.zip")

_LINE_WIDTH = 70

def _secret_for_question(index):
    secret = _open_secret(QUESTION_SECRETS[index - 1], "cli-contract:question:" + str(index))
    if secret is None:
        print("  [error] Could not open question quiz-data -- contact your instructor.")
        sys.exit(1)
    return secret

def _ask(q, index, total):
    secret = _secret_for_question(index)
    print(f"\n  Q{index:02}/{total:02}  {q['prompt']}")
    print(f"           Hint: {q['hint']}")
    attempts = 0
    while True:
        raw = input("  Your answer: ").strip()
        if not raw:
            continue
        if raw == secret["answer"]:
            if attempts > 0:
                for ln in _wrap(secret.get("explanation", "")):
                    print(ln)
            else:
                print(f"  Correct.  {secret.get('explanation', '')}")
            return raw
        attempts += 1
        _show_wrong(raw, secret.get("wrong") or {})
        print("           Run the binary again if you need to check.")

def _run_shell():
    if not os.path.isfile(REPO_ZIP):
        print("error: repo.zip not found.", file=sys.stderr)
        sys.exit(1)

    work_dir = tempfile.mkdtemp(prefix="cli-contract-")
    with zipfile.ZipFile(REPO_ZIP, "r") as zf:
        zf.extractall(work_dir)
    entries = os.listdir(work_dir)
    if len(entries) != 1:
        shutil.rmtree(work_dir, ignore_errors=True)
        print("error: unexpected zip structure", file=sys.stderr)
        sys.exit(1)
    repo_dir = os.path.join(work_dir, entries[0])

    # Compile cowfarm silently; remove source so the binary is a black box.
    src = os.path.join(repo_dir, "cowfarm.cpp")
    binary = os.path.join(repo_dir, "cowfarm")
    r = subprocess.run(
        ["g++", "-std=c++17", "-o", binary, src],
        capture_output=True, text=True,
    )
    if r.returncode != 0:
        shutil.rmtree(work_dir, ignore_errors=True)
        print("error: failed to build cowfarm:", file=sys.stderr)
        print(r.stderr, file=sys.stderr)
        sys.exit(1)
    os.remove(src)

    banner_text = """
      ============================================================
       Activity: CLI Contract Discovery
      ============================================================

       Step 1 -- read the usage message
         Run ./cowfarm with no arguments and read the output carefully.
       
       Step 2 -- explore the flags
         Try -h, --help, and --list.
       
       Step 3 -- meet every character
         Run ./cowfarm with each character name and a short message.
         Read the --list output and note each character's name exactly.
       
       Step 4 -- exit when you are ready
         exit
       
         The launcher will then ask you a few questions about what you found.
      ============================================================

    """
    rcfile = tempfile.NamedTemporaryFile(mode="w", suffix=".rc", delete=False)
    rcfile.write(
        f'PS1=\'\\u@cli-contract:\\W\\$ \'\n'
        f'cd "{repo_dir}"\n'
        "cat << \'BANNER\'\n" + banner_text + "\nBANNER\n"
    )
    rcfile.close()

    shell = os.environ.get("SHELL", "/bin/bash")
    try:
        subprocess.run([shell, "--rcfile", rcfile.name])
    finally:
        try:
            os.remove(rcfile.name)
        except OSError:
            pass

    shutil.rmtree(work_dir, ignore_errors=True)

